using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    bool res = design->designType(DirectDesignType);
    if (!res)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCirles = sketchCurves->sketchCircles();
    if (!sketchCirles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle = sketchCirles->addByCenterRadius(centerPoint, 10);
    if (!sketchCircle)
        return false;

    // Create a collection of entities for extrude
    Ptr entities0 = ObjectCollection::create();
    if (!entities0)
        return false;
    Ptr sketchProfiles = sketch->profiles();
    if (!sketchProfiles)
        return false;
    Ptr sketchProfile = sketchProfiles->item(0);
    if (!sketchProfile)
        return false;
    entities0->add(sketchProfile);

    // Create a cylinder with ExtrudeFeature using the profile above.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudeFeats = features->extrudeFeatures();
    if (!extrudeFeats)
        return false;
    Ptr extrudeFeatureInput =
        extrudeFeats->createInput(entities0, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeFeatureInput)
        return false;
    Ptr distance = adsk::core::ValueInput::createByReal(2.0);
    if (!distance)
        return false;
    extrudeFeatureInput->isSolid(true);
    extrudeFeatureInput->setDistanceExtent(false, distance);
    Ptr extrudeFeature = extrudeFeats->add(extrudeFeatureInput);
    if (!extrudeFeature)
        return false;

    // Create second body to do interference
    sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    sketchCirles = sketchCurves->sketchCircles();
    if (!sketchCirles)
        return false;
    centerPoint = Point3D::create(5, 0, 0);
    if (!centerPoint)
        return false;
    sketchCircle = sketchCirles->addByCenterRadius(centerPoint, 10);
    if (!sketchCircle)
        return false;

    entities0->clear();
    sketchProfiles = sketch->profiles();
    if (!sketchProfiles)
        return false;
    sketchProfile = sketchProfiles->item(0);
    if (!sketchProfile)
        return false;
    entities0->add(sketchProfile);

    // Create a cylinder with ExtrudeFeature using the profile above.
    extrudeFeatureInput =
        extrudeFeats->createInput(entities0, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeFeatureInput)
        return false;
    distance = adsk::core::ValueInput::createByReal(2.0);
    if (!distance)
        return false;
    extrudeFeatureInput->isSolid(true);
    extrudeFeatureInput->setDistanceExtent(false, distance);
    extrudeFeature = extrudeFeats->add(extrudeFeatureInput);
    if (!extrudeFeature)
        return false;

    // Create a collection of bodies
    Ptr bodies = adsk::core::ObjectCollection::create();
    if (!bodies)
        return false;
    Ptr brepBodies = rootComp->bRepBodies();
    if (!brepBodies)
        return false;
    for (auto body : brepBodies)
    {
        bodies->add(body);
    }

    // Create InterferenceInput
    Ptr input = design->createInterferenceInput(bodies);
    if (!input)
        return false;

    // Analyze interference
    Ptr results = design->analyzeInterference(input);
    if (!input)
        return false;

    // Create bodies
    results->createBodies(true);

    return true;
}
